import React, { useEffect, useState, useRef } from "react";
import API from "../../api/api";

export default function FreelancerChat() {
  const me = JSON.parse(localStorage.getItem("user") || "{}");
  const [contacts, setContacts] = useState([]);
  const [selected, setSelected] = useState(null);
  const [messages, setMessages] = useState([]);
  const [text, setText] = useState("");
  const [sending, setSending] = useState(false);
  const bottomRef = useRef(null);

  useEffect(() => {
    API.get("/messages/contacts").then(r => setContacts(r.data || [])).catch(() => {});
  }, []);

  useEffect(() => {
    if (!selected) return;
    API.get(`/messages/conversation/${selected.id}`).then(r => setMessages(r.data || [])).catch(() => {});
  }, [selected]);

  useEffect(() => { bottomRef.current?.scrollIntoView({behavior:"smooth"}); }, [messages]);

  const send = async () => {
    if (!text.trim() || !selected) return;
    setSending(true);
    try {
      await API.post("/messages", { receiver_id: selected.id, message: text });
      const r = await API.get(`/messages/conversation/${selected.id}`);
      setMessages(r.data || []);
      setText("");
    } catch {}
    setSending(false);
  };

  const fmtTime = (d) => d ? new Date(d).toLocaleTimeString("en-IN",{hour:"2-digit",minute:"2-digit"}) : "";
  const initials = (name) => name?.split(" ").map(n=>n[0]).join("").toUpperCase().slice(0,2) || "?";

  const S = {
    page: { background:"#0f172a", height:"100vh", display:"flex", flexDirection:"column", fontFamily:"'Segoe UI',sans-serif" },
    header: { padding:"20px 28px", borderBottom:"1px solid #1e293b" },
    title: { fontSize:"20px", fontWeight:"700", color:"#f1f5f9" },
    body: { display:"flex", flex:1, overflow:"hidden" },
    sidebar: { width:"260px", background:"#0d1526", borderRight:"1px solid #1e293b", display:"flex", flexDirection:"column", flexShrink:0 },
    sideHead: { padding:"16px 18px", fontSize:"11px", fontWeight:"700", color:"#475569", textTransform:"uppercase", letterSpacing:"1px", borderBottom:"1px solid #1e293b" },
    contact: (active) => ({ display:"flex", alignItems:"center", gap:"12px", padding:"14px 18px", cursor:"pointer", borderBottom:"1px solid #0f172a", background: active?"rgba(45,212,191,0.08)":"transparent", borderLeft: active?"3px solid #2dd4bf":"3px solid transparent", transition:"all 0.15s" }),
    avatar: (color) => ({ width:"36px", height:"36px", borderRadius:"50%", background:color, display:"flex", alignItems:"center", justifyContent:"center", fontSize:"13px", fontWeight:"800", color:"white", flexShrink:0 }),
    cName: { fontSize:"13px", fontWeight:"600", color:"#e2e8f0" },
    cPrev: { fontSize:"11px", color:"#475569", marginTop:"1px", overflow:"hidden", whiteSpace:"nowrap", textOverflow:"ellipsis", maxWidth:"160px" },
    main: { flex:1, display:"flex", flexDirection:"column", overflow:"hidden" },
    chatHead: { padding:"14px 22px", borderBottom:"1px solid #1e293b", display:"flex", alignItems:"center", gap:"12px" },
    chatName: { fontSize:"15px", fontWeight:"700", color:"#f1f5f9" },
    chatRole: { fontSize:"11px", color:"#64748b" },
    msgArea: { flex:1, overflowY:"auto", padding:"20px 22px", display:"flex", flexDirection:"column", gap:"10px" },
    bubble: (mine) => ({
      maxWidth:"65%", padding:"10px 14px", borderRadius: mine?"14px 14px 4px 14px":"14px 14px 14px 4px",
      background: mine?"linear-gradient(135deg,#0d9488,#0891b2)":"#1e293b",
      border: mine?"none":"1px solid #334155",
      alignSelf: mine?"flex-end":"flex-start",
    }),
    bubbleText: { fontSize:"13px", color:"#f1f5f9", lineHeight:1.5 },
    bubbleTime: (mine) => ({ fontSize:"10px", color: mine?"rgba(255,255,255,0.5)":"#475569", marginTop:"4px", textAlign: mine?"right":"left" }),
    inputRow: { padding:"14px 22px", borderTop:"1px solid #1e293b", display:"flex", gap:"10px", alignItems:"center" },
    input: { flex:1, padding:"10px 16px", background:"#1e293b", border:"1px solid #334155", borderRadius:"24px", color:"#f1f5f9", fontSize:"13px", outline:"none" },
    sendBtn: { width:"42px", height:"42px", borderRadius:"50%", border:"none", background:"linear-gradient(135deg,#0d9488,#0891b2)", color:"white", fontSize:"16px", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 },
    empty: { flex:1, display:"flex", alignItems:"center", justifyContent:"center", color:"#334155", fontSize:"14px" },
  };

  const colors = ["#0d9488","#0891b2","#7c3aed","#be185d","#b45309"];

  return (
    <div style={S.page}>
      <div style={S.header}><h1 style={S.title}>Messages</h1></div>
      <div style={S.body}>
        {/* SIDEBAR */}
        <div style={S.sidebar}>
          <div style={S.sideHead}>Conversations</div>
          {contacts.map((c,i) => (
            <div key={c.id} style={S.contact(selected?.id===c.id)} onClick={()=>setSelected(c)}>
              <div style={S.avatar(colors[i%colors.length])}>{initials(c.name)}</div>
              <div>
                <p style={S.cName}>{c.name}</p>
                <p style={S.cPrev}>{c.last_message||"Start a conversation"}</p>
              </div>
            </div>
          ))}
        </div>

        {/* MAIN */}
        <div style={S.main}>
          {!selected ? (
            <div style={S.empty}>Select a conversation to start messaging</div>
          ) : (
            <>
              <div style={S.chatHead}>
                <div style={S.avatar(colors[contacts.indexOf(selected)%colors.length])}>{initials(selected.name)}</div>
                <div><p style={S.chatName}>{selected.name}</p><p style={S.chatRole}>{selected.role}</p></div>
              </div>
              <div style={S.msgArea}>
                {messages.map((m,i) => {
                  const mine = m.sender_id === me.id;
                  return (
                    <div key={i} style={S.bubble(mine)}>
                      <p style={S.bubbleText}>{m.message}</p>
                      <p style={S.bubbleTime(mine)}>{fmtTime(m.created_at)}</p>
                    </div>
                  );
                })}
                <div ref={bottomRef} />
              </div>
              <div style={S.inputRow}>
                <input style={S.input} value={text} onChange={e=>setText(e.target.value)}
                  placeholder="Type a message..."
                  onKeyDown={e=>e.key==="Enter"&&!e.shiftKey&&send()} />
                <button style={S.sendBtn} onClick={send} disabled={sending}>➤</button>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
